// ============================================================
// VALIDAÇÃO, SANITIZAÇÃO E CONTEXTO DE RASTREABILIDADE
// ============================================================

const body = $input.first().json.body;

if (!body) throw new Error('[Validação] Body da requisição está ausente.');

const aba = body.aba;
if (!aba || typeof aba !== 'string') {
  throw new Error('[Validação] Campo "aba" ausente ou inválido.');
}

const abasPermitidas = ['requisitos', 'cronograma', 'dados_gerais'];
if (!abasPermitidas.includes(aba)) {
  throw new Error(`[Validação] Valor de "aba" não permitido: "${aba}".`);
}

function sanitize(value) {
  if (typeof value === 'string') {
    return value
      .replace(/ignore (all |previous |above |prior )?instructions?/gi, '[REMOVIDO]')
      .replace(/ system .*? prompt /gi, '[REMOVIDO]')
      .replace(/<[^>]{0,200}>/g, '')
      .substring(0, 8000);
  }
  if (Array.isArray(value)) return value.map(sanitize);
  if (typeof value === 'object' && value !== null) {
    return Object.fromEntries(Object.entries(value).map(([k, v]) => [k, sanitize(v)]));
  }
  return value;
}

const sanitizedBody = sanitize(body);

if (aba === 'dados_gerais') {
  const campo = sanitizedBody?.dados?.campo;
  const camposPermitidos = [
    'project_description', 'current_situation', 'previous_approvals',
    'scope_project', 'not_scope', 'alternatives_evaluated',
    'risks_plan_mitigation', 'qualitative_gains', 'potential_gains',
    'real_gains', 'financial_analytics', 'proposed_costs_notes'
  ];
  if (!campo || !camposPermitidos.includes(campo)) {
    throw new Error(`[Validação] Campo "dados.campo" inválido: "${campo}"`);
  }
}

if (aba === 'requisitos' && !sanitizedBody?.dados?.contexto?.dados_gerais) {
  throw new Error('[Validação] "dados.contexto.dados_gerais" ausente para aba requisitos.');
}

if (aba === 'cronograma' && !sanitizedBody?.dados?.contexto?.requisitos) {
  throw new Error('[Validação] "dados.contexto.requisitos" ausente para aba cronograma.');
}

const request_id = sanitizedBody.request_id || $execution.id;
const proposal_id = sanitizedBody?.dados?.proposal_id || sanitizedBody?.proposal_id || 'nao_informado';

return [{
  body: {
    ...sanitizedBody,
    request_id,
    proposal_id,
    schema_version: sanitizedBody.schema_version || '2.0.0'
  }
}];

const input = $input.first().json;
const texto = input.response;
const meta = input.observabilidade || {};

if (!texto) throw new Error("Campo 'response' não encontrado na entrada.");

let parsed;
try {
  const clean = String(texto).replace(/```json|```/g, '').trim();
  parsed = JSON.parse(clean);
} catch (error) {
  throw new Error('Erro ao fazer parse do JSON da IA: ' + error.message);
}

const requisitos = Object.values(parsed).map((r) => ({
  descricao: r['descrição'],
  criticidade: r['criticidade'],
  esforco: r['esforço']
}));

return [{
  resultado: { requisitos },
  meta: {
    ...meta,
    finished_at: new Date().toISOString()
  }
}];

const input = $input.first().json;
const rawResponse = input.response;
const meta = input.observabilidade || {};

try {
  if (!rawResponse) throw new Error('A resposta da IA veio vazia');

  const cleanData = String(rawResponse)
    .replace(/```json|```/g, '')
    .replace(/<[^>]*>/g, '')
    .trim();

  const parsed = JSON.parse(cleanData);

  if (!parsed.campo && !parsed.conteudo) {
    throw new Error('JSON retornado sem as chaves esperadas: campo/conteudo');
  }

  return [{
    resultado: parsed,
    meta: {
      ...meta,
      finished_at: new Date().toISOString()
    }
  }];
} catch (e) {
  throw new Error(`Falha ao processar resposta da IA | ${e.message}`);
}

const error = $input.first().json;
const errorMessage = error.message || error.error || 'Erro desconhecido';
const errorNode = error.node || 'nó desconhecido';
const timestamp = new Date().toISOString();
const requestId = error?.body?.request_id || error?.request_id || $execution.id;

console.error(JSON.stringify({
  timestamp,
  nivel: 'ERROR',
  request_id: requestId,
  no: errorNode,
  mensagem: errorMessage
}));

return [{
  erro: true,
  request_id: requestId,
  timestamp,
  mensagem: 'Ocorreu um erro ao processar a solicitação. Tente novamente.',
  detalhe_interno: errorMessage
}];

const payload = $input.first().json.body;

const startedAt = new Date().toISOString();
const observabilidade = {
  request_id: payload.request_id,
  proposal_id: payload.proposal_id,
  aba: payload.aba,
  schema_version: payload.schema_version,
  started_at: startedAt
};

console.log(JSON.stringify({ nivel: 'INFO', evento: 'workflow_start', ...observabilidade }));

return [{ body: payload, observabilidade }];
